use std::collections::BinaryHeap;
use std::cmp::Reverse;

pub fn huffman_coding(frequencies: &[i32]) -> i32 {
    if frequencies.len() <= 1 {
        return 0;
    }

    let mut min_heap: BinaryHeap<Reverse<i32>> = frequencies
        .iter()
        .map(|&f| Reverse(f))
        .collect();

    let mut total_cost = 0;
    while min_heap.len() > 1 {
        let Reverse(left) = min_heap.pop().unwrap();
        let Reverse(right) = min_heap.pop().unwrap();
        let merged = left + right;
        total_cost += merged;
        min_heap.push(Reverse(merged));
    }

    total_cost
}

import scala.collection.mutable

object HuffmanCoding {

  def huffmanCoding(frequencies: Array[Int]): Int = {
    if (frequencies.length <= 1) return 0

    val minHeap = mutable.PriorityQueue[Int]()(Ordering[Int].reverse)
    frequencies.foreach(minHeap.enqueue(_))

    var totalCost = 0
    while (minHeap.size > 1) {
      val left = minHeap.dequeue()
      val right = minHeap.dequeue()
      val merged = left + right
      totalCost += merged
      minHeap.enqueue(merged)
    }

    totalCost
  }
}

func huffmanCoding(_ frequencies: [Int]) -> Int {
    if frequencies.count <= 1 {
        return 0
    }

    var heap = frequencies.sorted()

    var totalCost = 0
    while heap.count > 1 {
        let left = heap.removeFirst()
        let right = heap.removeFirst()
        let merged = left + right
        totalCost += merged

        var insertIndex = 0
        while insertIndex < heap.count && heap[insertIndex] < merged {
            insertIndex += 1
        }
        heap.insert(merged, at: insertIndex)
    }

    return totalCost
}

export function huffmanCoding(frequencies: number[]): number {
    if (frequencies.length <= 1) {
        return 0;
    }

    const heap = [...frequencies];
    heap.sort((a, b) => a - b);

    let totalCost = 0;
    while (heap.length > 1) {
        const left = heap.shift()!;
        const right = heap.shift()!;
        const merged = left + right;
        totalCost += merged;

        let i = 0;
        while (i < heap.length && heap[i] < merged) {
            i++;
        }
        heap.splice(i, 0, merged);
    }

    return totalCost;
}
